{action_set_definitions}: {
  "get_order_info": {
    "description": "Retrieves the specific items, quantities, and status of a given Order ID.",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "The unique identifier of the order (e.g., 'ORD-707')."
        }
      },
      "required": [
        "order_id"
      ]
    },
    "example_output": {
      "order_id": "ORD-707",
      "items": [
        {
          "sku": "SKU-99",
          "quantity": 2
        }
      ],
      "destination": "International Air"
    }
  },
  "get_sku_hazmat_details": {
    "description": "Retrieves safety data for a SKU, including Hazard Class, Packing Group, and IATA volume limits for different transport modes.",
    "parameters": {
      "type": "object",
      "properties": {
        "sku_id": {
          "type": "string",
          "description": "The SKU ID to query."
        }
      },
      "required": [
        "sku_id"
      ]
    },
    "example_output": {
      "sku_id": "SKU-99",
      "hazard_class": "3",
      "packing_group": "II",
      "iata_passenger_air_limit_per_pkg": "5L",
      "unit_volume": "1L"
    }
  },
  "query_inventory_location": {
    "description": "Finds the specific warehouse zone/shelf where a SKU is stored.",
    "parameters": {
      "type": "object",
      "properties": {
        "sku_id": {
          "type": "string",
          "description": "The SKU ID to locate."
        }
      },
      "required": [
        "sku_id"
      ]
    },
    "example_output": {
      "sku_id": "SKU-99",
      "location_id": "ZONE-B-SHELF-12"
    }
  },
  "list_available_robots": {
    "description": "Lists all autonomous mobile robots (AMRs) that are currently idle and their locations.",
    "parameters": {
      "type": "object",
      "properties": {}
    },
    "example_output": {
      "robots": [
        {
          "robot_id": "AMR-01",
          "location": "CHARGING-STATION-A",
          "status": "IDLE"
        }
      ]
    }
  },
  "list_warehouse_zones": {
    "description": "Returns a list of zone IDs for specific warehouse functions like 'packing_station' or 'shipping_dock'.",
    "parameters": {
      "type": "object",
      "properties": {
        "zone_type": {
          "type": "string",
          "enum": [
            "packing_station",
            "shipping_dock",
            "inventory",
            "charging"
          ],
          "description": "The type of zone to find."
        }
      },
      "required": [
        "zone_type"
      ]
    },
    "example_output": {
      "zones": [
        "DOCK-NORTH-01",
        "DOCK-SOUTH-02"
      ]
    }
  },
  "get_compliant_packaging": {
    "description": "Retrieves a list of available packaging materials that meet specific IATA Packing Group requirements.",
    "parameters": {
      "type": "object",
      "properties": {
        "required_packing_group": {
          "type": "string",
          "description": "The required safety rating (e.g., 'I', 'II', or 'III')."
        },
        "transport_mode": {
          "type": "string",
          "description": "The mode of transport (e.g., 'Air-Passenger')."
        }
      },
      "required": [
        "required_packing_group",
        "transport_mode"
      ]
    },
    "example_output": {
      "packaging_options": [
        {
          "package_id": "BOX-HAZ-05",
          "max_volume": "10L",
          "rating": "II"
        }
      ]
    }
  },
  "execute_robot_task": {
    "description": "Commands a robot to move to a location, pick an item, or drop an item.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "action": {
          "type": "string",
          "enum": [
            "move",
            "pick",
            "drop"
          ]
        },
        "target_id": {
          "type": "string",
          "description": "The ID of the location or the SKU."
        },
        "quantity": {
          "type": "number",
          "description": "Required if action is pick/drop."
        }
      },
      "required": [
        "robot_id",
        "action",
        "target_id"
      ]
    },
    "example_output": {
      "status": "success",
      "current_location": "ZONE-B-SHELF-12"
    }
  },
  "finalize_and_document": {
    "description": "Finalizes the packing of the order and generates mandatory IATA DGR regulatory documentation (Shipper's Declaration).",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string"
        },
        "package_id": {
          "type": "string"
        },
        "skus_included": {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        "compliance_declaration": {
          "type": "boolean",
          "description": "Must be true to confirm IATA standards are met."
        }
      },
      "required": [
        "order_id",
        "package_id",
        "skus_included",
        "compliance_declaration"
      ]
    },
    "example_output": {
      "documentation_id": "DGR-DOC-2023-001",
      "status": "COMPLIANT"
    }
  }
}
